	m.HandleFunc("POST "+options.BaseURL+"/tickets/{ticketID}/trace", wrapper.LogStep)
	m.HandleFunc("POST "+options.BaseURL+"/tickets/{ticketID}/transitions", wrapper.TransitionTicket)

	return m
