// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Liveness/readiness
	// (GET /healthz)
	GetHealthz(ctx context.Context, request GetHealthzRequestObject) (GetHealthzResponseObject, error)
	// Lifetime stats for the authenticated agent (tickets created, reviews approved/rejected). For gamification.
	// (GET /me/stats)
	GetMeStats(ctx context.Context, request GetMeStatsRequestObject) (GetMeStatsResponseObject, error)
	// Daily activity counts for the last N days (for activity graph). Oldest day first.
	// (GET /me/stats/history)
	GetMeStatsHistory(ctx context.Context, request GetMeStatsHistoryRequestObject) (GetMeStatsHistoryResponseObject, error)
	// List organizations for the authenticated user (OAuth required)
	// (GET /orgs)
	ListOrgs(ctx context.Context, request ListOrgsRequestObject) (ListOrgsResponseObject, error)
	// Create organization (auth required)
	// (POST /orgs)
	CreateOrg(ctx context.Context, request CreateOrgRequestObject) (CreateOrgResponseObject, error)

	// (GET /orgs/{orgID})
	GetOrg(ctx context.Context, request GetOrgRequestObject) (GetOrgResponseObject, error)

	// (GET /orgs/{orgID}/projects)
	ListProjectsByOrg(ctx context.Context, request ListProjectsByOrgRequestObject) (ListProjectsByOrgResponseObject, error)

	// (POST /orgs/{orgID}/projects)
	CreateProject(ctx context.Context, request CreateProjectRequestObject) (CreateProjectResponseObject, error)
	// Get git notes for a commit (requires repo_path query; server returns 501 if repo not accessible)
	// (GET /orgs/{orgID}/projects/{projectID}/git-notes/commits/{commitSha})
	GetCommitNotes(ctx context.Context, request GetCommitNotesRequestObject) (GetCommitNotesResponseObject, error)
	// List commits with notes (requires repo_path query; server returns 501 if repo not accessible)
	// (GET /orgs/{orgID}/projects/{projectID}/git-notes/log)
	GetGitNotesLog(ctx context.Context, request GetGitNotesLogRequestObject) (GetGitNotesLogResponseObject, error)

	// (GET /projects/{projectID})
	GetProject(ctx context.Context, request GetProjectRequestObject) (GetProjectResponseObject, error)
	// Update project (e.g. set status to active or closed)
	// (PATCH /projects/{projectID})
	UpdateProject(ctx context.Context, request UpdateProjectRequestObject) (UpdateProjectResponseObject, error)

	// (GET /projects/{projectID}/escalations)
	ListEscalations(ctx context.Context, request ListEscalationsRequestObject) (ListEscalationsResponseObject, error)

	// (POST /projects/{projectID}/queue/claim)
	ClaimTicket(ctx context.Context, request ClaimTicketRequestObject) (ClaimTicketResponseObject, error)

	// (GET /projects/{projectID}/reviews)
	ListPendingReviews(ctx context.Context, request ListPendingReviewsRequestObject) (ListPendingReviewsResponseObject, error)

	// (GET /projects/{projectID}/tickets)
	ListTickets(ctx context.Context, request ListTicketsRequestObject) (ListTicketsResponseObject, error)

	// (POST /projects/{projectID}/tickets)
	CreateTicket(ctx context.Context, request CreateTicketRequestObject) (CreateTicketResponseObject, error)

	// (GET /tickets/{ticketID})
	GetTicket(ctx context.Context, request GetTicketRequestObject) (GetTicketResponseObject, error)

	// (PATCH /tickets/{ticketID})
	UpdateTicket(ctx context.Context, request UpdateTicketRequestObject) (UpdateTicketResponseObject, error)

	// (POST /tickets/{ticketID}/escalations/{escalationID}/resolve)
	ResolveEscalation(ctx context.Context, request ResolveEscalationRequestObject) (ResolveEscalationResponseObject, error)

	// (DELETE /tickets/{ticketID}/lease)
	ReleaseLease(ctx context.Context, request ReleaseLeaseRequestObject) (ReleaseLeaseResponseObject, error)

	// (POST /tickets/{ticketID}/lease/renew)
	RenewLease(ctx context.Context, request RenewLeaseRequestObject) (RenewLeaseResponseObject, error)

	// (POST /tickets/{ticketID}/reviews)
	CreateReview(ctx context.Context, request CreateReviewRequestObject) (CreateReviewResponseObject, error)
	// Execution trace (steps logged by the agent while working)
	// (GET /tickets/{ticketID}/trace)
	GetTrace(ctx context.Context, request GetTraceRequestObject) (GetTraceResponseObject, error)
	// Append a step to the execution trace (requires valid lease)
	// (POST /tickets/{ticketID}/trace)
	LogStep(ctx context.Context, request LogStepRequestObject) (LogStepResponseObject, error)
	// Transition ticket state (e.g. start, submit, approve, reject)
	// (POST /tickets/{ticketID}/transitions)
	TransitionTicket(ctx context.Context, request TransitionTicketRequestObject) (TransitionTicketResponseObject, error)
}

type StrictHandlerFunc = strictnethttp.StrictHTTPHandlerFunc
type StrictMiddlewareFunc = strictnethttp.StrictHTTPMiddlewareFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
	options     StrictHTTPServerOptions
}

